// ─── URL Extractor & Validator ────────────────────────────────
// Extracts URL from Telegram message text.
// Returns: { url, supported } — supported = true only for Amazon.
const message = $input.first()?.json?.message;
// ── Case 1: No message at all ──────────────────────────────────
if (!message) {
  return [{ json: { url: null, supported: false, reason: 'no_message', text: null } }];
}
// ── Extract raw text (handles plain text & caption on images) ──
const rawText = message.text ?? message.caption ?? '';
// ── Case 2: No text in message ─────────────────────────────────
if (!rawText.trim()) {
  return [{ json: { url: null, supported: false, reason: 'no_text', text: null } }];
}
// ── URL regex — catches all common formats ─────────────────────
const URL_REGEX = /https?:\/\/[^\s\)\]\}\,\"\'\\<\>]+/gi;
const found = rawText.match(URL_REGEX);
// ── Case 3: No URL found in text ───────────────────────────────
if (!found || found.length === 0) {
  return [{ json: { url: null, supported: false, reason: 'no_url_in_message', text: rawText } }];
}
// ── Amazon domain patterns (all known regional variants) ───────
const AMAZON_PATTERNS = [
  // Short links
  /^https?:\/\/a\.co\//i,           // a.co/d/0aQuRdfM
  /^https?:\/\/amzn\.to\//i,        // amzn.to/XXXXX
  /^https?:\/\/amzn\.eu\//i,        // amzn.eu/XXXXX (EU short link)
  // Standard country domains
  /^https?:\/\/(www\.)?amazon\.com(\/|$)/i,     // US
  /^https?:\/\/(www\.)?amazon\.co\.uk(\/|$)/i,  // UK
  /^https?:\/\/(www\.)?amazon\.de(\/|$)/i,     // Germany
  /^https?:\/\/(www\.)?amazon\.fr(\/|$)/i,     // France
  /^https?:\/\/(www\.)?amazon\.it(\/|$)/i,     // Italy
  /^https?:\/\/(www\.)?amazon\.es(\/|$)/i,     // Spain
  /^https?:\/\/(www\.)?amazon\.ca(\/|$)/i,     // Canada
  /^https?:\/\/(www\.)?amazon\.com\.au(\/|$)/i, // Australia
  /^https?:\/\/(www\.)?amazon\.co\.jp(\/|$)/i,  // Japan
  /^https?:\/\/(www\.)?amazon\.in(\/|$)/i,     // India
  /^https?:\/\/(www\.)?amazon\.com\.br(\/|$)/i, // Brazil
  /^https?:\/\/(www\.)?amazon\.com\.mx(\/|$)/i, // Mexico
  /^https?:\/\/(www\.)?amazon\.nl(\/|$)/i,     // Netherlands
  /^https?:\/\/(www\.)?amazon\.se(\/|$)/i,     // Sweden
  /^https?:\/\/(www\.)?amazon\.pl(\/|$)/i,     // Poland
  /^https?:\/\/(www\.)?amazon\.ae(\/|$)/i,     // UAE
  /^https?:\/\/(www\.)?amazon\.sa(\/|$)/i,     // Saudi Arabia
  /^https?:\/\/(www\.)?amazon\.sg(\/|$)/i,     // Singapore
  /^https?:\/\/(www\.)?amazon\.com\.tr(\/|$)/i, // Turkey
  /^https?:\/\/(www\.)?amazon\.eg(\/|$)/i,     // Egypt
  /^https?:\/\/(www\.)?amazon\.co\.za(\/|$)/i,  // South Africa
];
function isAmazon(url) {
  return AMAZON_PATTERNS.some(p => p.test(url));
}
// ── Pick first Amazon URL, else first URL found ────────────────
const amazonUrl = found.find(u => isAmazon(u));
const firstUrl  = amazonUrl ?? found[0];
return [{
  json: {
    url:       firstUrl,
    supported: isAmazon(firstUrl),
    reason:    isAmazon(firstUrl) ? 'amazon_url' : 'unsupported_domain',
    text:      rawText,
  },
}];

